class Solution {
public:
    int findMaxForm(vector<string>& strs, int m, int n) {
        vector<vector<int>> dp(m+1, vector<int>(n+1));
        for(auto& s:strs){
            int a=count(s.begin(),s.end(),'0'), b=s.size()-a;
            for(int i=m;i>=a;i--)
                for(int j=n;j>=b;j--)
                    dp[i][j]=max(dp[i][j], dp[i-a][j-b]+1);
        }
        return dp[m][n];
    }
};

