int findMaxForm(char** strs, int sn, int m, int n) {
    int dp[101][101]={0};
    for(int k=0;k<sn;k++){
        int a=0; for(char* p=strs[k];*p;p++) if(*p=='0') a++;
        int b=strlen(strs[k])-a;
        for(int i=m;i>=a;i--) for(int j=n;j>=b;j--)
            if(dp[i-a][j-b]+1>dp[i][j]) dp[i][j]=dp[i-a][j-b]+1;
    }
    return dp[m][n];
}
